import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import api from '../services/api';

const Shop = () => {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchProducts = async () => {
      try {
        const { data } = await api.get('/products');
        setProducts(data);
      } catch (error) {
        console.error('Error fetching products', error);
        // Fallback placeholder data if backend is not running
        setProducts([
          { _id: '1', name: 'Signature Trench', price: 850, imageUrl: '' },
          { _id: '2', name: 'Cashmere Knit', price: 420, imageUrl: '' },
          { _id: '3', name: 'Leather Boots', price: 650, imageUrl: '' },
          { _id: '4', name: 'Minimalist Tote', price: 580, imageUrl: '' },
        ]);
      } finally {
        setLoading(false);
      }
    };

    fetchProducts();
  }, []);

  return (
    <div className="container">
      <h1 className="page-title">Collection</h1>
      {loading ? (
        <p>Loading...</p>
      ) : (
        <div className="product-grid">
          {products.map((product) => (
            <Link to={`/product/${product._id}`} key={product._id} className="product-card">
              <div className="product-image" style={{ backgroundImage: `url(${product.imageUrl})`, backgroundSize: 'cover', backgroundPosition: 'center' }}></div>
              <div className="product-info">
                <span className="product-name">{product.name}</span>
                <span className="product-price">${product.price}</span>
              </div>
            </Link>
          ))}
        </div>
      )}
    </div>
  );
};

export default Shop;
